import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import api from '../utils/api';

const inp: React.CSSProperties = { width: '100%', padding: '10px 14px', border: '2px solid #e8e0d0', borderRadius: 10, fontSize: 14, fontFamily: 'inherit', outline: 'none', color: '#1a1a2e', background: '#fff' };
const lbl: React.CSSProperties = { display: 'block', fontSize: 12, fontWeight: 600, color: '#6b7280', marginBottom: 6 };

export default function Register() {
  const [form, setForm] = useState({ account_type: 'student', member_id: '', name: '', email: '', password: '', confirm_password: '', department: '', batch: '', mobile: '', address: '', gender: '' });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const set = (k: string, v: string) => setForm(f => ({ ...f, [k]: v }));

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    if (form.password !== form.confirm_password) { setError('Passwords do not match!'); return; }
    if (form.password.length < 6) { setError('Password must be at least 6 characters!'); return; }
    setLoading(true);
    try {
      await api.post('/auth/register', { ...form });
      setSuccess('Registration successful! Please wait for librarian approval before logging in.');
      setTimeout(() => navigate('/login'), 3000);
    } catch (e: any) {
      setError(e.response?.data?.message || 'Registration failed');
    } finally { setLoading(false); }
  };

  return (
    <div style={{ minHeight: '100vh', background: '#f5f0e8', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20 }}>
      <div style={{ width: '100%', maxWidth: 600, background: '#fff', borderRadius: 20, padding: 36, boxShadow: '0 8px 40px rgba(26,26,46,0.1)' }}>
        {/* Header */}
        <div style={{ textAlign: 'center', marginBottom: 28 }}>
          <div style={{ width: 48, height: 48, background: '#1a1a2e', borderRadius: 12, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 22, margin: '0 auto 12px' }}>📖</div>
          <h1 style={{ fontFamily: "'Playfair Display',serif", fontSize: 26, fontWeight: 700, color: '#1a1a2e' }}>Create Account</h1>
          <p style={{ fontSize: 13, color: '#9ca3af', marginTop: 4 }}>Register to access the library</p>
        </div>

        {error && <div style={{ background: '#fee2e2', color: '#dc2626', padding: '12px 16px', borderRadius: 10, fontSize: 13, marginBottom: 16 }}>{error}</div>}
        {success && <div style={{ background: '#d1fae5', color: '#059669', padding: '12px 16px', borderRadius: 10, fontSize: 13, marginBottom: 16 }}>{success}</div>}

        <form onSubmit={handleSubmit}>
          {/* Account Type */}
          <div style={{ marginBottom: 20 }}>
            <label style={lbl}>Account Type *</label>
            <div style={{ display: 'flex', gap: 10 }}>
              {['student', 'staff'].map(type => (
                <button key={type} type="button" onClick={() => set('account_type', type)}
                  style={{ flex: 1, padding: '10px', border: `2px solid ${form.account_type === type ? '#1a1a2e' : '#e8e0d0'}`, borderRadius: 10, background: form.account_type === type ? '#1a1a2e' : '#fff', color: form.account_type === type ? '#fff' : '#6b7280', fontSize: 14, fontWeight: 600, cursor: 'pointer', fontFamily: 'inherit', textTransform: 'capitalize', transition: 'all .2s' }}>
                  {type === 'student' ? '🎓 Student' : '👨‍💼 Staff'}
                </button>
              ))}
            </div>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 14 }}>
            {/* ID */}
            <div>
              <label style={lbl}>{form.account_type === 'student' ? 'Student ID *' : 'Staff ID *'}</label>
              <input style={inp} value={form.member_id} onChange={e => set('member_id', e.target.value)} placeholder={form.account_type === 'student' ? 'e.g. 20210101' : 'e.g. 10001'} required />
            </div>

            {/* Name */}
            <div>
              <label style={lbl}>Full Name *</label>
              <input style={inp} value={form.name} onChange={e => set('name', e.target.value)} placeholder="Your full name" required />
            </div>

            {/* Department */}
            <div>
              <label style={lbl}>Department *</label>
              <input style={inp} value={form.department} onChange={e => set('department', e.target.value)} placeholder="e.g. Computer Science" required />
            </div>

            {/* Batch - only for student */}
            {form.account_type === 'student' && (
              <div>
                <label style={lbl}>Batch *</label>
                <input style={inp} value={form.batch} onChange={e => set('batch', e.target.value)} placeholder="e.g. 2021" required />
              </div>
            )}

            {/* Mobile */}
            <div>
              <label style={lbl}>Mobile Number *</label>
              <input style={inp} value={form.mobile} onChange={e => set('mobile', e.target.value)} placeholder="01XXXXXXXXX" required />
            </div>

            {/* Gender */}
            <div>
              <label style={lbl}>Gender *</label>
              <select style={inp} value={form.gender} onChange={e => set('gender', e.target.value)} required>
                <option value="">Select gender</option>
                <option value="male">Male</option>
                <option value="female">Female</option>
                <option value="other">Other</option>
              </select>
            </div>

            {/* Email */}
            <div>
              <label style={lbl}>Email Address *</label>
<input 
  style={inp} 
  type="email" 
  value={form.email} onChange={e => set('email', e.target.value.toLowerCase())} placeholder="your@email.com" required />
            </div>

            {/* Password */}
            <div>
              <label style={lbl}>Password *</label>
              <input style={inp} type="password" value={form.password} onChange={e => set('password', e.target.value)} placeholder="Min 6 characters" required />
            </div>

            {/* Confirm Password */}
            <div>
              <label style={lbl}>Confirm Password *</label>
              <input style={inp} type="password" value={form.confirm_password} onChange={e => set('confirm_password', e.target.value)} placeholder="Repeat password" required />
            </div>

            {/* Address */}
            <div style={{ gridColumn: '1/-1' }}>
              <label style={lbl}>Address</label>
              <textarea style={{ ...inp, minHeight: 70, resize: 'vertical' }} value={form.address} onChange={e => set('address', e.target.value)} placeholder="Your full address" />
            </div>
          </div>

          <button type="submit" disabled={loading}
            style={{ width: '100%', padding: 13, background: '#1a1a2e', color: '#fff', border: 'none', borderRadius: 12, fontSize: 15, fontWeight: 600, cursor: 'pointer', fontFamily: 'inherit', marginTop: 20, opacity: loading ? 0.7 : 1 }}>
            {loading ? 'Registering...' : 'Create Account →'}
          </button>
        </form>

        <p style={{ textAlign: 'center', fontSize: 13, color: '#6b7280', marginTop: 16 }}>
          Already have an account?{' '}
          <Link to="/login" style={{ color: '#1a1a2e', fontWeight: 600, textDecoration: 'none' }}>Sign in</Link>
        </p>

        <div style={{ marginTop: 16, background: '#fef3c7', borderRadius: 10, padding: 12, fontSize: 12, color: '#92400e' }}>
          ⚠️ After registration, your account needs <strong>librarian approval</strong> before you can login.
        </div>
      </div>
    </div>
  );
}
